pub struct NodeView<T> { pub value: Option<T>, pub next: i32, pub prev: i32 }

impl<T: View> View for Node<T> {
    type V = NodeView<T::V>;
    closed spec fn view(&self) -> NodeView<T::V> {
        NodeView {
            value: self.value@,
            next: self.next,
            prev: self.prev,
        }
    }
}

